},
["custom"] = "function(allstates, event, ...)\n    if event == \"UNIT_AURA\" then\n        local unit, updateInfo = ...    \n        \n        if updateInfo.isFullUpdate and next(allstates) then\n            local auraInstanceIds = C_UnitAuras.GetUnitAuraInstanceIDs(unit, \"HELPFUL\")\n            local foundStates = {}\n            for i, auraInstanceID in ipairs(auraInstanceIds) do\n                if allstates[auraInstanceID] then\n                    foundStates[auraInstanceID] = true \n                end \n            end\n            \n            for k, v in pairs(allstates) do\n                if not foundStates[k] then\n                    allstates:Remove(k) \n                end \n            end\n        end\n        \n        if updateInfo.addedAuras then\n            for i, auraData in ipairs(updateInfo.addedAuras) do                \n                local auraInstanceID = auraData.auraInstanceID\n                local isExternalDefensive = not C_UnitAuras.IsAuraFilteredOutByInstanceID(\"player\", auraInstanceID, \"HELPFUL|EXTERNAL_DEFENSIVE\")\n                if isExternalDefensive then\n                    local duration = C_UnitAuras.GetAuraDuration(unit, auraInstanceID)\n                    if duration then\n                        \n                        allstates:Update(auraInstanceID, {\n                                progressType = \"durationObject\",\n                                duration = duration:GetTotalDuration(),\n                                expirationTime = duration:GetEndTime(),\n                                durationObject = duration,\n                                name = auraData.name,\n                                icon = auraData.icon,\n                                unit = auraData.sourceUnit,\n                                autoHide = true,\n                        })\n                    end\n                end\n            end\n        end \n        \n        if updateInfo.updatedAuraInstanceIDs then\n            for i, auraInstanceID in ipairs(updateInfo.updatedAuraInstanceIDs)  do\n                if allstates[auraInstanceID]  then\n                    local auraData = C_UnitAuras.GetAuraDataByAuraInstanceID(unit, auraInstanceID)\n                    local duration = C_UnitAuras.GetAuraDuration(unit, auraInstanceID)\n                    if duration then\n                        \n                        allstates:Update(auraInstanceID, {\n                                progressType = \"durationObject\",\n                                duration = duration:GetTotalDuration(),\n                                expirationTime = duration:GetEndTime(),\n                                durationObject = duration,\n                                name = auraData.name,\n                                icon = auraData.icon,\n                                unit = auraData.sourceUnit,\n                                autoHide = true,\n                        })\n                    end\n                end\n            end\n        end\n        \n        if updateInfo.removedAuraInstanceIDs then\n            for i, auraInstanceID in ipairs(updateInfo.removedAuraInstanceIDs)  do\n                if allstates[auraInstanceID]  then                    \n                    allstates:Remove(auraInstanceID)\n                end\n            end\n        end\n    elseif event == \"OPTIONS\" then\n        for i=1,3 do\n            local duration = C_DurationUtil.CreateDuration()\n            duration:SetTimeFromStart(GetTime(), 5)\n            allstates:Update(i, {\n                    progressType = \"timed\",\n                    duration = duration:GetTotalDuration(),\n                    expirationTime = duration:GetEndTime(),\n                    durationObject = duration,\n                    icon = C_Spell.GetSpellTexture(102342),\n                    name = C_Spell.GetSpellName(102342),\n                    unit = \"player\",\n                    autoHide = true,\n            }) \n        end\n    end\nend",
